// ╔══════════════════════════════════════════════════════╗
// ║  CONFIGURATION — Edit these values to customise     ║
// ╚══════════════════════════════════════════════════════╝
const CONFIG = {
  // Delete executions older than this many days
  RETENTION_DAYS: 30,

  // Maximum executions to process per run (safety limit)
  MAX_PER_RUN: 5000,

  // Batch size for API pagination
  BATCH_SIZE: 100,

  // Email recipient for the cleanup report
  EMAIL_RECIPIENT: 'fabian@fdnxt.com',

  // Google Sheet ID for the central TAS_N8N_Audit sheet
  SHEET_ID: $env.TAS_AUDIT_SHEET_ID || 'YOUR_GOOGLE_SHEET_ID_HERE',

  // Tab name within the audit sheet
  SHEET_TAB: 'Execution_Cleanup',

  // Which execution statuses to clean up
  STATUSES_TO_CLEAN: ['success', 'error'],

  // Set to false for dry-run / report-only mode
  AUTO_DELETE: true
};

return [{ json: CONFIG }];

const config = $('⚙️ Configuration').first().json;
const BASE_URL = $env.N8N_BASE_URL;
const API_KEY = $env.N8N_API_KEY;

const cutoffDate = new Date();
cutoffDate.setDate(cutoffDate.getDate() - config.RETENTION_DAYS);
const cutoffISO = cutoffDate.toISOString();

const stats = {
  totalScanned: 0,
  totalDeleted: 0,
  totalFailed: 0,
  totalSkipped: 0,
  byStatus: {},
  byWorkflow: {},
  errors: [],
  oldestFound: null,
  newestDeleted: null
};

for (const status of config.STATUSES_TO_CLEAN) {
  stats.byStatus[status] = { scanned: 0, deleted: 0, failed: 0 };
  let hasMore = true;
  let cursor = null;

  while (hasMore && stats.totalScanned < config.MAX_PER_RUN) {
    let url = `${BASE_URL}/api/v1/executions?limit=${config.BATCH_SIZE}&status=${status}`;
    if (cursor) url += `&cursor=${cursor}`;

    let listResp;
    try {
      listResp = await this.helpers.httpRequest({
        method: 'GET',
        url,
        headers: { 'X-N8N-API-KEY': API_KEY }
      });
    } catch (err) {
      stats.errors.push(`Failed to list ${status} executions: ${err.message}`);
      break;
    }

    const executions = listResp.data || [];
    cursor = listResp.nextCursor;
    hasMore = !!cursor && executions.length === config.BATCH_SIZE;

    for (const ex of executions) {
      stats.totalScanned++;
      stats.byStatus[status].scanned++;

      const finishedAt = new Date(ex.stoppedAt || ex.startedAt);

      // Track oldest execution found
      if (!stats.oldestFound || finishedAt < new Date(stats.oldestFound)) {
        stats.oldestFound = finishedAt.toISOString();
      }

      if (finishedAt >= cutoffDate) {
        stats.totalSkipped++;
        continue;
      }

      // Track by workflow
      const wfName = ex.workflowData?.name || ex.workflowId || 'unknown';
      if (!stats.byWorkflow[wfName]) stats.byWorkflow[wfName] = { deleted: 0, failed: 0 };

      if (!config.AUTO_DELETE) {
        stats.totalSkipped++;
        continue;
      }

      try {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `${BASE_URL}/api/v1/executions/${ex.id}`,
          headers: { 'X-N8N-API-KEY': API_KEY }
        });
        stats.totalDeleted++;
        stats.byStatus[status].deleted++;
        stats.byWorkflow[wfName].deleted++;

        if (!stats.newestDeleted || finishedAt > new Date(stats.newestDeleted)) {
          stats.newestDeleted = finishedAt.toISOString();
        }
      } catch (err) {
        stats.totalFailed++;
        stats.byStatus[status].failed++;
        stats.byWorkflow[wfName].failed++;
        stats.errors.push(`Delete ${ex.id}: ${err.message}`);
      }
    }
  }
}

return [{
  json: {
    ...stats,
    retentionDays: config.RETENTION_DAYS,
    cutoffDate: cutoffISO,
    dryRun: !config.AUTO_DELETE,
    runAt: new Date().toISOString(),
    emailRecipient: config.EMAIL_RECIPIENT,
    sheetId: config.SHEET_ID,
    topWorkflows: Object.entries(stats.byWorkflow)
      .sort((a, b) => b[1].deleted - a[1].deleted)
      .slice(0, 20)
      .map(([name, counts]) => ({ name, ...counts }))
  }
}];
